    for (var newStory in newStories) {
      bool exists = false;
      for (var item in data) {
        if (item['id'] == newStory['id']) {
          exists = true;
          // Update it
          item['title'] = newStory['title'];
          item['category'] = newStory['category'];
          item['reference_text'] = newStory['reference_text'];
          item['story_text'] = newStory['story_text'];
          item['lesson'] = newStory['lesson'];
          item['source'] = newStory['source'];
